const email = $json;

function decodeBase64Url(value) {
  if (!value) return '';
  const normalized = String(value).replace(/-/g, '+').replace(/_/g, '/');
  const padded = normalized.padEnd(normalized.length + ((4 - normalized.length % 4) % 4), '=');
  return Buffer.from(padded, 'base64').toString('utf8');
}

function collectParts(part, output = []) {
  if (!part) return output;
  if (part.mimeType && part.body?.data) {
    output.push({ mimeType: part.mimeType, text: decodeBase64Url(part.body.data) });
  }
  if (Array.isArray(part.parts)) {
    for (const child of part.parts) collectParts(child, output);
  }
  return output;
}

const headers = Object.fromEntries((email.payload?.headers || []).map((header) => [String(header.name || '').toLowerCase(), header.value || '']));
const parts = collectParts(email.payload);
const plain = parts.find((part) => /text\/plain/i.test(part.mimeType))?.text || '';
const html = parts.find((part) => /text\/html/i.test(part.mimeType))?.text || '';
const body = plain || html.replace(/<[^>]*>/g, ' ') || email.textPlain || email.textHtml || email.snippet || '';
const from = email.from || headers.from || '';

return {
  json: {
    id: email.id || email.messageId,
    messageId: email.id || email.messageId,
    threadId: email.threadId,
    from,
    subject: email.subject || headers.subject || '',
    snippet: email.snippet || '',
    body,
    email_ts: email.internalDate ? new Date(Number(email.internalDate)).toISOString() : new Date().toISOString()
  }
};

const result = $json;
const rawPhone = String(result.phone || '').replace(/\D/g, '');
const toPhone = rawPhone ? (rawPhone.startsWith('+') ? rawPhone : `+${rawPhone}`) : '';
const fromPhone = String($env.YCLOUD_WHATSAPP_FROM || '+59178096231').trim();

if (!toPhone || !fromPhone || !result.replyText) {
  return { json: { shouldSend: false, reason: 'missing phone or text', result } };
}

return {
  json: {
    shouldSend: true,
    result,
    ycloudRequest: {
      from: fromPhone,
      to: toPhone,
      type: 'text',
      text: {
        body: result.replyText
      }
    }
  }
};

