const email = $('Normalize Mercantil Email').first().json;
const agent = $input.first().json || {};
const raw = String(agent.output || agent.text || agent.response || agent.message?.content || '').trim();
let parsed = null;
const jsonStart = raw.indexOf('{');
const jsonEnd = raw.lastIndexOf('}');
const jsonText = jsonStart >= 0 && jsonEnd > jsonStart ? raw.slice(jsonStart, jsonEnd + 1) : raw;
try {
  parsed = JSON.parse(jsonText);
} catch (error) {
  parsed = null;
}

function parseAmount(value) {
  if (typeof value === 'number') return value;
  if (typeof value !== 'string') return null;
  const match = value.match(/[\d.,]+/);
  if (!match) return null;
  const normalized = match[0].replace(/\./g, '').replace(',', '.');
  const amount = Number(normalized);
  return Number.isFinite(amount) ? amount : null;
}

const confidence = Number(parsed?.confidence || 0);
const aiEmailEvidence = {
  isMercantilCreditQr: parsed?.isMercantilCreditQr === true,
  amount: parseAmount(parsed?.amount),
  payerName: parsed?.payerName ? String(parsed.payerName).slice(0, 160) : null,
  concept: parsed?.concept ? String(parsed.concept).slice(0, 160) : null,
  notificationNumber: parsed?.notificationNumber ? String(parsed.notificationNumber).slice(0, 80) : null,
  transactionAtText: parsed?.transactionAtText ? String(parsed.transactionAtText).slice(0, 120) : null,
  confidence: Number.isFinite(confidence) ? Math.max(0, Math.min(1, confidence)) : 0,
  safeToUse: parsed?.safeToUse !== false,
  reason: String(parsed?.reason || raw || '').slice(0, 240)
};

return [{ json: { ...email, aiEmailEvidence } }];
